#include <stdio.h>
#include <stdlib.h>
#define MAXN 1000
#define MAXM 1000
#define MAXQ 1000000

int parent[MAXN * MAXM];
int rank[MAXN * MAXM];
int walls[MAXN][MAXM][4]; // 0: up, 1: down, 2: left, 3: right

int find(int x) {
    if (parent[x] != x) {
        parent[x] = find(parent[x]);
    }
    return parent[x];
}

void unionSet(int x, int y) {
    int rootX = find(x);
    int rootY = find(y);
    if (rootX != rootY) {
        if (rank[rootX] > rank[rootY]) {
            parent[rootY] = rootX;
        } else if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY;
        } else {
            parent[rootY] = rootX;
            rank[rootX]++;
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, Q;
        scanf("%d %d %d", &N, &M, &Q);
        for (int i = 0; i < N * M; i++) {
            parent[i] = i;
            rank[i] = 0;
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                walls[i][j][0] = walls[i][j][1] = walls[i][j][2] = walls[i][j][3] = 0;
            }
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M - 1; j++) {
                unionSet(i * M + j, i * M + j + 1);
            }
        }
        for (int i = 0; i < N - 1; i++) {
            for (int j = 0; j < M; j++) {
                unionSet(i * M + j, (i + 1) * M + j);
            }
        }
        int sum = 0;
        for (int i = 0; i < Q; i++) {
            int type;
            scanf("%d", &type);
            if (type == 1) {
                int x, y;
                scanf("%d %d", &x, &y);
                x--;
                y--;
                int index1 = x * M + y;
                int index2 = x * M + y + 1;
                if (find(index1) == find(index2)) {
                    // do nothing
                } else {
                    walls[x][y][3] = 1;
                    walls[x][y + 1][2] = 1;
                }
            } else if (type == 2) {
                int x, y;
                scanf("%d %d", &x, &y);
                x--;
                y--;
                int index1 = x * M + y;
                int index2 = (x + 1) * M + y;
                if (find(index1) == find(index2)) {
                    // do nothing
                } else {
                    walls[x][y][1] = 1;
                    walls[x + 1][y][0] = 1;
                }
            } else if (type == 3) {
                int x1, y1, x2, y2;
                scanf("%d %d %d %d", &x1, &y1, &x2, &y2);
                x1--;
                y1--;
                x2--;
                y2--;
                int index1 = x1 * M + y1;
                int index2 = x2 * M + y2;
                if (find(index1) == find(index2)) {
                    sum++;
                }
            } else if (type == 4) {
                int maxSize = 0;
                for (int j = 0; j < N * M; j++) {
                    int size = 0;
                    for (int k = 0; k < N * M; k++) {
                        if (find(k) == find(j)) {
                            size++;
                        }
                    }
                    maxSize = (size > maxSize) ? size : maxSize;
                }
                sum += maxSize;
            }
        }
        printf("%d\n", sum);
    }
    return 0;
}

